def _parse_list(s):
    return [x.strip() for x in s.split("|") if x.strip()]


def build_career(raw):
    name, cat, desc, stream, edu_ug, edu_pg, exams, insts, sal_s, sal_m, sal_sr, growth, skills, nature, pros, challenges = raw
    return {
        "name": name,
        "slug": _slug(name),
        "category": cat,
        "description": desc,
        "stream": stream,
        "education": {"undergraduate": edu_ug, "postgraduate": edu_pg},
        "entrance_exams": _parse_list(exams),
        "top_institutions": _parse_list(insts),
        "salary": {"starting": sal_s, "mid_career": sal_m, "senior": sal_sr},
        "growth_outlook": growth,
        "skills_required": _parse_list(skills),
        "nature_of_work": nature,
        "pros": _parse_list(pros),
        "challenges": _parse_list(challenges),
    }


def get_all_careers():
    return [build_career(r) for r in _RAW]


def get_categories():
    return CATEGORIES


def get_careers_by_category(cat_id):
    return [build_career(r) for r in _RAW if r[1] == cat_id]


def get_career_by_slug(slug):
    for r in _RAW:
        if _slug(r[0]) == slug:
            return build_career(r)
    return None


def get_category_counts():
    counts = {}
    for r in _RAW:
        counts[r[1]] = counts.get(r[1], 0) + 1
    return counts
